function fetchData(){fetch("/api/data").then(t=>t.json()).then(t=>{let e="<h2>Device Data</h2>";for(const[a,n]of Object.entries(t))e+=`<p><strong>${a}:</strong> ${n}</p>`;document.getElementById("dataDisplay").innerHTML=e}).catch(t=>{console.error("Error fetching data:",t),document.getElementById("dataDisplay").innerHTML="<h2>Device Data</h2><p>Error loading data</p>"})}fetchData(),setInterval(fetchData,5e3);